B.a49=new A.x9(B.a_,B.br,null,null,B.LK,B.K,null)
B.af7=new A.a8r(null)
B.afp=new A.jp("1. Acerca de esta Pol\xedtica","En esta Pol\xedtica de Privacidad se describe c\xf3mo procesamos tus datos personales en AirPulse AB.\n\nSe aplica a todos los servicios de streaming de AirPulse como usuario, incluyendo tu uso de AirPulse en cualquier dispositivo, la personalizaci\xf3n de tu experiencia de usuario, la infraestructura obligatoria para prestar nuestros servicios, la conexi\xf3n de tu cuenta con otra aplicaci\xf3n, y nuestras opciones de streaming gratuitas y pagas.\n\nDe vez en cuando, podemos desarrollar nuevos servicios u ofrecer servicios adicionales. Esos servicios tambi\xe9n estar\xe1n sujetos a esta Pol\xedtica, a menos que se indique lo contrario cuando los presentemos.",null)
B.afl=new A.jp("2. Derechos y controles sobre tus datos personales","Muchas leyes de privacidad otorgan derechos a las personas sobre sus datos personales. Estas leyes incluyen el Reglamento General de Protecci\xf3n de Datos (RGPD).\n\nTienes los siguientes derechos sobre tus datos personales:",null)
B.afe=new A.ml("Informaci\xf3n","Estar informado acerca de los datos personales que procesamos sobre ti y c\xf3mo los procesamos.",null)
B.afd=new A.ml("Acceso",'Solicitar acceso a los datos personales que procesamos sobre ti. Puedes utilizar la herramienta "Descargar tus datos" en la p\xe1gina Privacidad de la cuenta o ponerte en contacto con nosotros.',null)
B.aff=new A.ml("Rectificaci\xf3n","Solicitar que modifiquemos o actualicemos datos personales que sean imprecisos o est\xe9n incompletos. Puedes editar tus datos en la secci\xf3n Editar perfil de tu cuenta.",null)
B.afa=new A.ml("Eliminaci\xf3n","Solicitar que eliminemos algunos de tus datos personales. Hay situaciones en las que AirPulse no puede eliminar tus datos, por ejemplo cuando a\xfan es necesario procesarlos para la finalidad con la que los recolectamos.",null)
B.afc=new A.ml("Restricci\xf3n","Solicitar que dejemos de procesar todos o algunos de tus datos personales, de forma temporal o permanente.",null)
B.af8=new A.ml("Oposici\xf3n","Oponerte a que procesemos tus datos personales, especialmente cuando se usan para anuncios personalizados.",null)
B.afb=new A.ml("Portabilidad de datos","Solicitar una copia de tus datos personales en formato electr\xf3nico y transmitirlos para que se usen en el servicio de otra entidad.",null)
B.af9=new A.ml("Revocaci\xf3n de consentimiento","Revocar tu consentimiento de recopilaci\xf3n o uso de tus datos personales en cualquier momento.",null)
B.afo=new A.jp("3. Datos personales que recopilamos sobre ti","Recopilamos los siguientes tipos de datos personales:\n\n\u2022 Datos del usuario: nombre de visualizaci\xf3n, direcci\xf3n de email, contrase\xf1a, n\xfamero de tel\xe9fono, fecha de nacimiento, g\xe9nero, direcci\xf3n, pa\xeds.\n\n\u2022 Datos de uso: informaci\xf3n sobre c\xf3mo usas AirPulse (b\xfasquedas, historial de reproducci\xf3n, playlists, configuraci\xf3n, interacciones), datos t\xe9cnicos (URL, cookies, IP, ID del dispositivo, sistema operativo), y tu ubicaci\xf3n general (pa\xeds, regi\xf3n, ciudad).\n\n\u2022 Datos de voz: si las funciones de voz est\xe1n disponibles y otorgaste el permiso.\n\n\u2022 Datos de mensajes: si los mensajes est\xe1n disponibles y elegiste usar la funci\xf3n.\n\n\u2022 Datos de pagos y compras: nombre, fecha de nacimiento, m\xe9todo de pago, historial de pago.\n\n\u2022 Datos de encuestas e investigaciones: datos que nos proporcionas al responder encuestas o participar en investigaciones.",null)
B.afk=new A.jp("4. Objetivo de la utilizaci\xf3n de tus datos personales","Utilizamos tus datos personales para:\n\n\u2022 Proporcionar el Servicio de AirPulse de acuerdo con nuestro contrato contigo.\n\u2022 Personalizar tu cuenta y recomendaciones de contenido.\n\u2022 Diagnosticar, solucionar y arreglar errores del servicio.\n\u2022 Evaluar y desarrollar nuevas funciones y tecnolog\xedas.\n\u2022 Fines de marketing y publicidad (con tu consentimiento cuando sea requerido).\n\u2022 Cumplir con obligaciones legales y contractuales.\n\u2022 Mantener la seguridad del servicio y detectar fraudes.\n\u2022 Procesar tus pagos.\n\u2022 Realizar investigaciones y encuestas.\n\nLos fundamentos jur\xeddicos que amparan el procesamiento son: ejecuci\xf3n de contrato, inter\xe9s leg\xedtimo, consentimiento y cumplimiento de obligaciones legales.",null)
B.afq=new A.jp("5. C\xf3mo compartimos tus datos personales","Ciertos datos estar\xe1n siempre disponibles p\xfablicamente: tu nombre de perfil, foto de perfil, playlists p\xfablicas y otro contenido que publiques.\n\nPodemos compartir tus datos con:\n\n\u2022 Proveedores de servicios que nos ayudan a operar el servicio.\n\u2022 Socios de pago para procesar tus transacciones.\n\u2022 Socios de publicidad para ofrecerte anuncios m\xe1s relevantes.\n\u2022 Otras empresas de AirPulse para operaciones comerciales diarias.\n\u2022 Investigadores acad\xe9micos en formato seud\xf3nimo.\n\u2022 Tribunales y autoridades cuando sea legalmente requerido.\n\nCompartimos contigo el control: solo compartiremos datos con terceros opcionales si eliges usar una funci\xf3n que lo requiera o si nos das permiso expl\xedcito.",null)
B.afi=new A.jp("6. Retenci\xf3n de datos","Conservamos tus datos personales solo por el tiempo necesario para brindarte el Servicio de AirPulse y para finalidades comerciales leg\xedtimas y esenciales.\n\n\u2022 Algunos datos se retienen hasta que t\xfa los elimines.\n\u2022 Ciertos datos expiran despu\xe9s de un per\xedodo espec\xedfico (p. ej., consultas se eliminan tras 90 d\xedas).\n\u2022 Algunos datos se retienen hasta que se elimine tu cuenta de AirPulse.\n\u2022 Los datos de verificaci\xf3n de edad se eliminan de inmediato luego de completar la verificaci\xf3n.",null)
B.afg=new A.jp("7. Transferencia a otros pa\xedses","Debido a la naturaleza global de nuestro negocio, AirPulse comparte tus datos personales a nivel internacional. Las transferencias a pa\xedses dentro de la UE/EEE se basan en Decisiones de adecuaci\xf3n. Las transferencias a otros pa\xedses est\xe1n protegidas por Cl\xe1usulas contractuales est\xe1ndar (SCC).\n\nImplementamos protecciones adicionales como cifrado, seudonimizaci\xf3n y evaluaciones de impacto de transferencias.",null)
B.afh=new A.jp("8. C\xf3mo mantenemos seguros tus datos personales","Implementamos las medidas t\xe9cnicas y organizativas adecuadas para proteger la seguridad de tus datos personales, incluyendo pol\xedticas de seudonimizaci\xf3n, cifrado, acceso y retenci\xf3n.\n\nPara proteger tu cuenta, te recomendamos:\n\n\u2022 Usar una contrase\xf1a segura exclusiva para AirPulse.\n\u2022 Nunca compartir tu contrase\xf1a con nadie.\n\u2022 Cerrar sesi\xf3n al terminar en dispositivos compartidos.\n\u2022 Limitar el acceso a tu computadora y navegador.",null)
B.afn=new A.jp("9. Ni\xf1os","El Servicio de AirPulse tiene un l\xedmite de edad m\xednima en cada pa\xeds o regi\xf3n. Si no cumples con ese l\xedmite, no crees ni uses el Servicio est\xe1ndar de AirPulse.\n\nNo recopilamos ni usamos deliberadamente datos personales de ni\xf1os menores del l\xedmite de edad aplicable. Si eres padre/madre o responsable legal y te das cuenta de que tu hijo proporcion\xf3 datos personales a AirPulse, comun\xedcate con nosotros de inmediato.",null)
B.afm=new A.jp("10. Cambios a esta Pol\xedtica","Es posible que, ocasionalmente, realicemos cambios a esta Pol\xedtica. Cuando realicemos cambios importantes, te proporcionaremos un aviso destacado de forma adecuada, por ejemplo mostrando un aviso en el Servicio de AirPulse o envi\xe1ndote una notificaci\xf3n por email.",null)
B.afj=new A.jp("11. C\xf3mo ponerte en contacto con nosotros","",null)
B.af6=new A.a8q(null)
